// Cache bust: 2025-11-02T18:42:45.777Z
import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';
import './i18n/config';

// Early mobile optimizations - before React loads
if (typeof window !== 'undefined') {
  // Detect mobile device early
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
  const isLowEndDevice = navigator.hardwareConcurrency <= 2 || navigator.deviceMemory <= 2;

  if (isMobile || isLowEndDevice) {
    // Add performance classes immediately
    document.documentElement.classList.add('mobile-device');
    if (isLowEndDevice) {
      document.documentElement.classList.add('low-end-device');
    }

    // Disable smooth scrolling on mobile for better performance
    document.documentElement.style.scrollBehavior = 'auto';

    // Set viewport height variable for mobile browsers
    const setVH = () => {
      const vh = window.innerHeight * 0.01;
      document.documentElement.style.setProperty('--vh', `${vh}px`);
    };
    setVH();
    window.addEventListener('resize', setVH, { passive: true });
    window.addEventListener('orientationchange', () => setTimeout(setVH, 200), { passive: true });
  }

  // Remove loading class when React is ready
  const removeInitialLoading = () => {
    document.body.classList.add('loaded');
    const loadingEl = document.querySelector('.initial-loading');
    if (loadingEl) {
      setTimeout(() => loadingEl.remove(), 300);
    }
  };

  // Initialize React app
  const root = ReactDOM.createRoot(document.getElementById('root'));
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );

  // Remove loading state after React renders
  setTimeout(removeInitialLoading, 100);
} else {
  // Server-side rendering fallback
  const root = ReactDOM.createRoot(document.getElementById('root'));
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
}
